1	import { Alert, Drawer, Empty, Flex, Select, Spin, Table, Tabs, Tag, Typography } from 'antd';
2	import type { ColumnsType } from 'antd/es/table';
3	import { useMemo, useState } from 'react';
4	
5	import {
6	  getRun,
7	  listPipelineRuns,
8	  listRuns,
9	  type PipelineRun,
10	  type Result,
11	  type ResultStatus,
12	  type Run,
13	  type RunStatus,
14	  RUN_STATUSES,
15	} from '../api/runs';
16	import { type Check, listChecks, listSuites } from '../api/suites';
17	import { useAsyncData } from '../hooks/useAsyncData';
18	import {
19	  formatDuration,
20	  formatTimestamp,
21	  pipelineStatusColor,
22	  RESULT_STATUS_COLORS,
23	  RUN_STATUS_COLORS,
24	} from '../components/results/resultsFormat';
25	import { ScalarValue } from '../components/results/ScalarValue';
26	
27	const LIST_LIMIT = 200;
28	
29	export function Results() {
30	  return (
31	    <Flex vertical gap={24}>
32	      <Typography.Title level={3} style={{ margin: 0 }}>
33	        Results
34	      </Typography.Title>
35	      <Tabs
36	        defaultActiveKey="runs"
37	        items={[
38	          { key: 'runs', label: 'Runs', children: <RunsTab /> },
39	          { key: 'pipelines', label: 'Pipeline runs', children: <PipelineRunsTab /> },
40	        ]}
41	      />
42	    </Flex>
43	  );
44	}
45	
46	// ───────────────────────────── Runs tab ─────────────────────────────
47	
48	function RunsTab() {
49	  // Fetch a page of runs + the accessible suites (for id→name), then filter by
50	  // status client-side — cheap at this volume and avoids a refetch per filter.
51	  const { state } = useAsyncData(() => listRuns({ limit: LIST_LIMIT }));
52	  const { state: suitesState } = useAsyncData(listSuites);
53	  const [status, setStatus] = useState<RunStatus | 'all'>('all');
54	  const [openRun, setOpenRun] = useState<Run | null>(null);
55	
56	  const suiteNames = useMemo(() => {
57	    const map = new Map<string, string>();
58	    if (suitesState.status === 'ok') {
59	      for (const s of suitesState.data) map.set(s.id, s.name);
60	    }
61	    return map;
62	  }, [suitesState]);
63	
64	  if (state.status === 'loading') return <Spin tip="Loading runs…" size="large" />;
65	  if (state.status === 'error') {
66	    return <Alert type="error" showIcon message="Failed to load runs" description={state.error} />;
67	  }
68	
69	  const runs = status === 'all' ? state.data : state.data.filter((r) => r.status === status);
70	
71	  const columns: ColumnsType<Run> = [
72	    {
73	      title: 'Suite',
74	      dataIndex: 'suite_id',
75	      render: (suiteId: string) =>
76	        suiteNames.get(suiteId) ?? <Typography.Text code>{suiteId.slice(0, 8)}</Typography.Text>,
77	    },
78	    {
79	      title: 'Status',
80	      dataIndex: 'status',
81	      width: 120,
82	      render: (s: RunStatus) => <Tag color={RUN_STATUS_COLORS[s]}>{s}</Tag>,
83	    },
84	    { title: 'Triggered by', dataIndex: 'triggered_by', render: (t: string | null) => t ?? '—' },
85	    {
86	      title: 'Started',
87	      dataIndex: 'started_at',
88	      render: (t: string | null) => formatTimestamp(t),
89	    },
90	    {
91	      title: 'Duration',
92	      width: 110,
93	      render: (_: unknown, run: Run) => formatDuration(run.started_at, run.finished_at),
94	    },
95	  ];
96	
97	  return (
98	    <Flex vertical gap={16}>
99	      <Flex gap={12} align="center">
100	        <Typography.Text type="secondary">Status</Typography.Text>
101	        <Select<RunStatus | 'all'>
102	          value={status}
103	          onChange={setStatus}
104	          style={{ width: 160 }}
105	          options={[
106	            { value: 'all', label: 'All' },
107	            ...RUN_STATUSES.map((s) => ({ value: s, label: s })),
108	          ]}
109	        />
110	      </Flex>
111	      <Table<Run>
112	        rowKey="id"
113	        columns={columns}
114	        dataSource={runs}
115	        pagination={false}
116	        locale={{ emptyText: <Empty description="No runs yet." /> }}
117	        onRow={(run) => ({ onClick: () => setOpenRun(run), style: { cursor: 'pointer' } })}
118	      />
119	      <RunDetailDrawer
120	        run={openRun}
121	        suiteName={openRun ? (suiteNames.get(openRun.suite_id) ?? null) : null}
122	        onClose={() => setOpenRun(null)}
123	      />
124	    </Flex>
125	  );
126	}
127	
128	// ─────────────────────────── Run detail drawer ──────────────────────
129	
130	function RunDetailDrawer({
131	  run,
132	  suiteName,
133	  onClose,
134	}: {
135	  run: Run | null;
136	  suiteName: string | null;
137	  onClose: () => void;
138	}) {
139	  return (
140	    <Drawer
141	      open={run !== null}
142	      onClose={onClose}
143	      width={640}
144	      title={run ? `Run · ${suiteName ?? run.suite_id.slice(0, 8)}` : 'Run'}
145	      destroyOnClose
146	    >
147	      {/* Keyed by run id so switching runs (without closing) remounts and
148	          refetches — useAsyncData only fetches on mount/reload, not on prop
149	          change, so without the key the drawer would show the prior run. */}
150	      {run && <RunDetailBody key={run.id} run={run} />}
151	    </Drawer>
152	  );
153	}
154	
155	function RunDetailBody({ run }: { run: Run }) {
156	  // Remounted per run via the `key` at the call site → these fetch fresh.
157	  const { state } = useAsyncData(() => getRun(run.id));
158	  const { state: checksState } = useAsyncData(() => listChecks(run.suite_id));
159	
160	  const checks = useMemo(() => {
161	    const map = new Map<string, Check>();
162	    if (checksState.status === 'ok') {
163	      for (const c of checksState.data) map.set(c.id, c);
164	    }
165	    return map;
166	  }, [checksState]);
167	
168	  return (
169	    <Flex vertical gap={16}>
170	      <Flex gap={16} wrap>
171	        <Meta label="Status">
172	          <Tag color={RUN_STATUS_COLORS[run.status]}>{run.status}</Tag>
173	        </Meta>
174	        <Meta label="Triggered by">{run.triggered_by ?? '—'}</Meta>
175	        <Meta label="Started">{formatTimestamp(run.started_at)}</Meta>
176	        <Meta label="Duration">{formatDuration(run.started_at, run.finished_at)}</Meta>
177	      </Flex>
178	
179	      {state.status === 'loading' && <Spin tip="Loading results…" />}
180	      {state.status === 'error' && (
181	        <Alert type="error" showIcon message="Failed to load results" description={state.error} />
182	      )}
183	      {state.status === 'ok' && <ResultsTable results={state.data.results} checks={checks} />}
184	    </Flex>
185	  );
186	}
187	
188	function ResultsTable({ results, checks }: { results: Result[]; checks: Map<string, Check> }) {
189	  if (results.length === 0) {
190	    return <Empty description="No check results — the run did not complete." />;
191	  }
192	  const columns: ColumnsType<(typeof results)[number]> = [
193	    {
194	      title: 'Check',
195	      dataIndex: 'check_id',
196	      render: (id: string) =>
197	        checks.get(id)?.name ?? <Typography.Text code>{id.slice(0, 8)}</Typography.Text>,
198	    },
199	    {
200	      title: 'Expectation',
201	      dataIndex: 'check_id',
202	      render: (id: string) => (
203	        <Typography.Text type="secondary" style={{ fontSize: 12 }}>
204	          {checks.get(id)?.expectation_type ?? '—'}
205	        </Typography.Text>
206	      ),
207	    },
208	    {
209	      title: 'Status',
210	      dataIndex: 'status',
211	      width: 100,
212	      render: (s: ResultStatus) => <Tag color={RESULT_STATUS_COLORS[s]}>{s}</Tag>,
213	    },
214	    {
215	      title: 'Metric',
216	      dataIndex: 'metric_value',
217	      width: 90,
218	      render: (v: number | null) => (v === null ? '—' : v),
219	    },
220	    {
221	      title: 'Observed',
222	      dataIndex: 'observed_value',
223	      render: (v: Record<string, unknown> | null) => <ScalarValue value={v} />,
224	    },
225	  ];
226	  return (
227	    <Table rowKey="id" size="small" columns={columns} dataSource={results} pagination={false} />
228	  );
229	}
230	
231	// ─────────────────────────── Pipeline runs tab ──────────────────────
232	
233	function PipelineRunsTab() {
234	  const { state } = useAsyncData(() => listPipelineRuns({ limit: LIST_LIMIT }));
235	  const [provider, setProvider] = useState<'all' | 'adf' | 'airflow'>('all');
236	
237	  if (state.status === 'loading') return <Spin tip="Loading pipeline runs…" size="large" />;
238	  if (state.status === 'error') {
239	    return (
240	      <Alert
241	        type="error"
242	        showIcon
243	        message="Failed to load pipeline runs"
244	        description={state.error}
245	      />
246	    );
247	  }
248	
249	  const rows = provider === 'all' ? state.data : state.data.filter((p) => p.provider === provider);
250	
251	  const columns: ColumnsType<PipelineRun> = [
252	    { title: 'Provider', dataIndex: 'provider', width: 110, render: (p: string) => <Tag>{p}</Tag> },
253	    { title: 'Pipeline / DAG', dataIndex: 'pipeline_or_dag_id' },
254	    { title: 'Env', dataIndex: 'env', width: 80, render: (e: string) => e.toUpperCase() },
255	    {
256	      title: 'Status',
257	      dataIndex: 'status',
258	      width: 110,
259	      render: (s: string) => <Tag color={pipelineStatusColor(s)}>{s}</Tag>,
260	    },
261	    {
262	      title: 'Started',
263	      dataIndex: 'started_at',
264	      render: (t: string | null) => formatTimestamp(t),
265	    },
266	    {
267	      title: 'Failure reason',
268	      dataIndex: 'failure_reason',
269	      render: (r: string | null) => r ?? '—',
270	    },
271	  ];
272	
273	  return (
274	    <Flex vertical gap={16}>
275	      <Flex gap={12} align="center">
276	        <Typography.Text type="secondary">Provider</Typography.Text>
277	        <Select<'all' | 'adf' | 'airflow'>
278	          value={provider}
279	          onChange={setProvider}
280	          style={{ width: 160 }}
281	          options={[
282	            { value: 'all', label: 'All' },
283	            { value: 'adf', label: 'ADF' },
284	            { value: 'airflow', label: 'Airflow' },
285	          ]}
286	        />
287	      </Flex>
288	      <Table<PipelineRun>
289	        rowKey="id"
290	        columns={columns}
291	        dataSource={rows}
292	        pagination={false}
293	        locale={{ emptyText: <Empty description="No pipeline runs monitored yet." /> }}
294	      />
295	    </Flex>
296	  );
297	}
