1	import {
2	  App,
3	  Alert,
4	  Button,
5	  Drawer,
6	  Empty,
7	  Flex,
8	  List,
9	  Progress,
10	  Spin,
11	  Tag,
12	  Typography,
13	} from 'antd';
14	import { useEffect, useRef, useState } from 'react';
15	import { Link } from 'react-router-dom';
16	
17	import {
18	  cancelRun,
19	  getRunProgress,
20	  type ResultStatus,
21	  type RunProgress,
22	  type RunStatus,
23	} from '../../api/runs';
24	import { RESULT_STATUS_COLORS, RUN_STATUS_COLORS } from '../results/resultsFormat';
25	
26	/** Run lifecycle states past which polling stops. */
27	const TERMINAL: readonly RunStatus[] = ['succeeded', 'failed', 'cancelled'];
28	const DEFAULT_POLL_MS = 1500;
29	
30	function isTerminal(status: RunStatus): boolean {
31	  return TERMINAL.includes(status);
32	}
33	
34	/** antd Progress bar status from the run lifecycle. */
35	function barStatus(status: RunStatus): 'success' | 'exception' | 'active' | 'normal' {
36	  if (status === 'succeeded') return 'success';
37	  if (status === 'failed' || status === 'cancelled') return 'exception';
38	  if (status === 'running') return 'active';
39	  return 'normal';
40	}
41	
42	/**
43	 * Live run-progress drawer — opens on a queued run and polls
44	 * `GET /runs/{id}/progress` until the run is terminal, showing the run
45	 * lifecycle, a completed/total bar, and per-check status (a spinner while a
46	 * check is still pending). An editor can cancel an in-flight run.
47	 *
48	 * Mounted controlled by `runId`; pass `null` to keep it closed. The body is
49	 * keyed by `runId` so opening a different run remounts and restarts polling
50	 * rather than continuing the prior run's loop.
51	 */
52	export function LiveRunProgress({
53	  runId,
54	  suiteName,
55	  canManage,
56	  pollMs = DEFAULT_POLL_MS,
57	  onClose,
58	}: {
59	  runId: string | null;
60	  suiteName: string | null;
61	  canManage: boolean;
62	  /** Poll interval; overridable so tests can drive it deterministically. */
63	  pollMs?: number;
64	  onClose: () => void;
65	}) {
66	  return (
67	    <Drawer
68	      open={runId !== null}
69	      onClose={onClose}
70	      width={560}
71	      title={`Run progress${suiteName ? ` · ${suiteName}` : ''}`}
72	      destroyOnClose
73	    >
74	      {runId !== null && (
75	        <LiveRunProgressBody key={runId} runId={runId} canManage={canManage} pollMs={pollMs} />
76	      )}
77	    </Drawer>
78	  );
79	}
80	
81	function LiveRunProgressBody({
82	  runId,
83	  canManage,
84	  pollMs,
85	}: {
86	  runId: string;
87	  canManage: boolean;
88	  pollMs: number;
89	}) {
90	  const { message } = App.useApp();
91	  const [progress, setProgress] = useState<RunProgress | null>(null);
92	  const [error, setError] = useState<string | null>(null);
93	  const [cancelling, setCancelling] = useState(false);
94	  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
95	
96	  // Poll until terminal via a self-scheduling timeout (not setInterval, so a slow
97	  // request can't pile up overlapping fetches). `active` guards a late resolution
98	  // after unmount. Polling stops on a terminal status or a fetch error — the
99	  // latter surfaces an alert rather than hot-looping a broken endpoint.
100	  useEffect(() => {
101	    let active = true;
102	    const tick = async () => {
103	      try {
104	        const next = await getRunProgress(runId);
105	        if (!active) return;
106	        setProgress(next);
107	        setError(null);
108	        if (!isTerminal(next.status)) {
109	          timerRef.current = setTimeout(tick, pollMs);
110	        }
111	      } catch (err) {
112	        if (!active) return;
113	        setError(err instanceof Error ? err.message : String(err));
114	      }
115	    };
116	    void tick();
117	    return () => {
118	      active = false;
119	      if (timerRef.current) clearTimeout(timerRef.current);
120	    };
121	  }, [runId, pollMs]);
122	
123	  const onCancel = async () => {
124	    setCancelling(true);
125	    try {
126	      const run = await cancelRun(runId);
127	      // Reflect the terminal state immediately; the in-flight poll (if any) will
128	      // also resolve to it and stop.
129	      setProgress((p) => (p ? { ...p, status: run.status, finished_at: run.finished_at } : p));
